#!/usr/bin/env python3
"""Generate lawyers.html for jsjunshao admin"""
out = '/var/www/jsjunshao-admin/public/lawyers.html'

# CSS
css = ':root{--primary:#1B3A5C;--accent:#C9A84C;--bg:#f4f7fa;--white:#fff;--text:#333;--text-light:#888;--border:#e2e8f0;--radius:8px}*{margin:0;padding:0;box-sizing:border-box}body{font-family:"Noto Sans SC",sans-serif;background:var(--bg);color:var(--text)}.navbar{background:var(--primary);color:#fff;padding:16px 24px;display:flex;justify-content:space-between;align-items:center}.navbar h1{font-size:18px;font-weight:500}.navbar a{color:#fff;text-decoration:none;font-size:14px;opacity:.8}.navbar a:hover{opacity:1}.container{max-width:1200px;margin:0 auto;padding:32px 24px}.page-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:24px}.page-header h2{font-size:24px;color:var(--primary)}.btn{padding:10px 20px;border-radius:var(--radius);border:none;cursor:pointer;font-size:14px;font-weight:500}.btn-primary{background:var(--primary);color:#fff}.btn-primary:hover{background:#152e47}.card{background:var(--white);border-radius:var(--radius);padding:24px;box-shadow:0 2px 8px rgba(0,0,0,.06)}.search-bar{display:flex;gap:12px;margin-bottom:20px;align-items:center}.search-bar input{flex:1;padding:10px 14px;border:1px solid var(--border);border-radius:var(--radius);font-size:14px}.search-bar select{padding:10px 14px;border:1px solid var(--border);border-radius:var(--radius);font-size:14px}table{width:100%;border-collapse:collapse;font-size:14px}th{text-align:left;padding:12px 16px;border-bottom:2px solid var(--border);color:var(--text-light);font-weight:500;font-size:13px}td{padding:14px 16px;border-bottom:1px solid var(--border);vertical-align:middle}tr:last-child td{border-bottom:none}tr:hover{background:#f8fafc}.tag{display:inline-block;padding:2px 8px;border-radius:4px;font-size:12px;background:#e8f0fe;color:var(--primary);margin:2px}.tag-partner{background:#fef3c7;color:#92400e}.bio-preview{max-width:300px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;color:var(--text-light);font-size:13px}.actions-cell{white-space:nowrap}.actions-cell button{padding:6px 12px;border-radius:4px;border:1px solid var(--border);background:#fff;cursor:pointer;font-size:13px;margin-right:6px}.actions-cell button:hover{background:var(--bg)}.actions-cell .delete{color:#dc2626;border-color:#fecaca}.actions-cell .delete:hover{background:#fef2f2}.modal{display:none;position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,.5);z-index:1000;align-items:center;justify-content:center}.modal.show{display:flex}.modal-content{background:#fff;border-radius:var(--radius);padding:32px;width:90%;max-width:600px;max-height:90vh;overflow-y:auto}.modal-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:24px}.modal-header h3{font-size:18px;color:var(--primary)}.modal-close{background:none;border:none;font-size:24px;cursor:pointer;color:var(--text-light)}.form-field{margin-bottom:16px}.form-field label{display:block;font-size:13px;font-weight:500;margin-bottom:6px}.form-field input,.form-field textarea,.form-field select{width:100%;padding:10px 12px;border:1px solid var(--border);border-radius:var(--radius);font-size:14px;font-family:inherit}.form-field textarea{min-height:80px;resize:vertical}.modal-actions{display:flex;justify-content:flex-end;gap:12px;margin-top:24px}.btn-outline{background:#fff;border:1px solid var(--border);color:var(--text)}.btn-outline:hover{background:var(--bg)}.loading{text-align:center;padding:60px;color:var(--text-light)}.empty-state{text-align:center;padding:60px;color:var(--text-light)}.toast{position:fixed;bottom:24px;right:24px;background:var(--primary);color:#fff;padding:12px 20px;border-radius:var(--radius);font-size:14px;z-index:2000;opacity:0;transition:opacity .3s}.toast.show{opacity:1}.toast.error{background:#dc2626}.toast.success{background:#16a34a}.photo-upload-group{display:flex;gap:8px;align-items:center}.upload-btn{border:1px solid var(--border);background:#fff;padding:8px 16px;border-radius:var(--radius);cursor:pointer;font-size:13px}.upload-btn:hover{background:var(--bg)}.drag-handle{cursor:grab;color:#bbb;font-size:18px;display:inline-block;padding:0 4px;-webkit-user-select:none}.drag-handle:active{cursor:grabbing}tr.dragging{opacity:.4;background:#f0f7ff}tr.drag-over td{background:#e8f0fe}th.sortable{cursor:pointer;-webkit-user-select:none}th.sortable:hover{color:var(--primary)}th.sort-asc::after{content:" \\2191";font-size:11px;opacity:1}th.sort-desc::after{content:" \\2193";font-size:11px;opacity:1}th.sortable::after{content:" \\2195";font-size:10px;opacity:.4}'

body = '''<nav class="navbar"><h1>君劭律师事务所 · 管理后台</h1><a href="../index.html">返回前台 →</a></nav>
<div class="container">
<div class="page-header"><h2>律师团队</h2><button class="btn btn-primary" onclick="openModal()">+ 新增律师</button></div>
<div class="card">
<div class="search-bar"><input type="text" id="searchInput" placeholder="搜索律师姓名..." oninput="handleSearch()"><select id="roleFilter" onchange="handleSearch()"><option value="">全部角色</option><option value="partner">合伙人</option><option value="associate">执业律师</option></select></div>
<div id="tableContainer"><div class="loading">加载中...</div></div>
</div></div>
<div class="modal" id="lawyerModal"><div class="modal-content"><div class="modal-header"><h3 id="modalTitle">新增律师</h3><button class="modal-close" onclick="closeModal()">x</button></div>
<form id="lawyerForm" onsubmit="handleSubmit(event)"><input type="hidden" id="editId">
<div class="form-field"><label>姓名 *</label><input type="text" id="fName" required placeholder="请输入律师姓名"></div>
<div class="form-field"><label>职务头衔</label><input type="text" id="fTitle" placeholder="如：高级合伙人"></div>
<div class="form-field"><label>角色</label><select id="fRole" required><option value="partner">合伙人</option><option value="associate">执业律师</option></select></div>
<div class="form-field"><label>简介</label><textarea id="fBio" placeholder="律师简介"></textarea></div>
<div class="form-field"><label>专业标签（逗号分隔）</label><input type="text" id="fTags" placeholder="公司法, 知识产权"></div>
<div class="form-field"><label>照片</label><div class="photo-upload-group"><input type="text" id="fPhotoUrl" placeholder="照片URL（上传后自动填充）" style="flex:1;min-width:0;"><label class="btn btn-outline upload-btn" style="white-space:nowrap;cursor:pointer;">选择图片<input type="file" id="fPhotoUpload" accept="image/jpeg,image/png,image/gif,image/webp" style="display:none;" onchange="handlePhotoUpload(this)"></label></div><div id="photoPreview" style="margin-top:8px;"></div><div id="uploadProgress" style="display:none;color:#666;font-size:12px;margin-top:4px;">上传中...</div></div>
<div class="modal-actions"><button type="button" class="btn btn-outline" onclick="closeModal()">取消</button><button type="submit" class="btn btn-primary">保存</button></div>
</form></div></div>
<div class="toast" id="toast"></div>'''

js = '''var API="/api";var lawyers=[];var filtered=[];var currentSort={field:"sort_order",dir:"asc"};var dragSrcIndex=-1;
function getHeaders(){return{"Content-Type":"application/json","Authorization":"Bearer "+localStorage.getItem("token")}}
function checkAuth(){if(!localStorage.getItem("token")){window.location.href="login.html";return false}return true}
async function loadLawyers(){if(!checkAuth())return;try{var res=await fetch(API+"/lawyers",{headers:getHeaders()});if(res.status===401){window.location.href="login.html";return}if(!res.ok)throw new Error("Failed");var data=await res.json();lawyers=data.lawyers||data;filtered=lawyers.slice();handleSearch()}catch(e){document.getElementById("tableContainer").innerHTML='<div class="empty-state">加载失败</div>'}}
function handleSearch(){var q=document.getElementById("searchInput").value.toLowerCase();var role=document.getElementById("roleFilter").value;filtered=lawyers.filter(function(l){return(!role||l.role===role)&&(!q||(l.name&&l.name.toLowerCase().indexOf(q)!==-1)||(l.title&&l.title.toLowerCase().indexOf(q)!==-1))});renderTable()}
function toggleSort(field){if(currentSort.field===field){currentSort.dir=currentSort.dir==="asc"?"desc":"asc"}else{currentSort.field=field;currentSort.dir="asc"}renderTable()}
function handleDragStart(e,index){dragSrcIndex=index;e.dataTransfer.effectAllowed="move";var row=e.target.closest?e.target.closest("tr"):null;if(row)setTimeout(function(){row.classList.add("dragging")},0)}
function handleDragOver(e){e.preventDefault();e.dataTransfer.dropEffect="move";var rows=document.querySelectorAll("#tableContainer tbody tr");for(var i=0;i<rows.length;i++)rows[i].classList.remove("drag-over");var row=e.target.closest?e.target.closest("tr"):null;if(row)row.classList.add("drag-over")}
function handleDrop(e,targetIndex){e.preventDefault();if(dragSrcIndex===-1||dragSrcIndex===targetIndex)return;var moved=lawyers.splice(dragSrcIndex,1)[0];lawyers.splice(targetIndex,0,moved);var updates=[];for(var i=0;i<lawyers.length;i++){updates.push({id:lawyers[i].id,sort_order:i+1});lawyers[i].sort_order=i+1}var rows=document.querySelectorAll("#tableContainer tbody tr");for(var j=0;j<rows.length;j++)rows[j].classList.remove("dragging","drag-over");dragSrcIndex=-1;showToast("\\u6b63\\u5728\\u4fdd\\u5b58\\u987a\\u5e8f...","success");Promise.all(updates.map(function(u){return fetch(API+"/lawyers/"+u.id,{method:"PUT",headers:getHeaders(),body:JSON.stringify({sort_order:u.sort_order})})})).then(function(results){var allOk=results.every(function(r){return r.ok});showToast(allOk?"\\u6392\\u5e8f\\u5df2\\u4fdd\\u5b58":"\\u90e8\\u5206\\u4fdd\\u5b58\\u5931\\u8d25",allOk?"success":"error")}).catch(function(){showToast("\\u4fdd\\u5b58\\u5931\\u8d25","error")});renderTable()}
function handleDragEnd(e){var rows=document.querySelectorAll("#tableContainer tbody tr");for(var i=0;i<rows.length;i++)rows[i].classList.remove("dragging","drag-over");dragSrcIndex=-1}
function renderTable(){var sorted=filtered.slice().sort(function(a,b){var va,vb;if(currentSort.field==="name"){va=a.name||"";vb=b.name||""}else if(currentSort.field==="title"){va=a.title||"";vb=b.title||""}else if(currentSort.field==="role"){va=a.role||"";vb=b.role||""}else if(currentSort.field==="tags"){va=(a.tags||[]).join(",");vb=(b.tags||[]).join(",")}else{va=a.sort_order||0;vb=b.sort_order||0}if(typeof va==="number"){return currentSort.dir==="asc"?va-vb:vb-va}var cmp=va.localeCompare?va.localeCompare(vb,"zh"):String(va).localeCompare(String(vb),"zh");return currentSort.dir==="asc"?cmp:-cmp});document.querySelectorAll("th.sortable").forEach(function(th){th.classList.remove("sort-asc","sort-desc");if(th.dataset.sort===currentSort.field){th.classList.add(currentSort.dir==="asc"?"sort-asc":"sort-desc")}});var container=document.getElementById("tableContainer");if(sorted.length===0){container.innerHTML='<div class="empty-state">\\u6682\\u65e0\\u5f8b\\u5e08\\u6570\\u636e\\uff0c\\u70b9\\u51fb\\u53f3\\u4e0a\\u89d2\\u65b0\\u589e</div>';return}var html='<table><thead><tr><th style="width:40px;"></th>';var cols=[{sort:"name",label:"\\u59d3\\u540d"},{sort:"title",label:"\\u804c\\u52a1"},{sort:"role",label:"\\u89d2\\u8272"},{sort:"tags",label:"\\u4e13\\u4e1a\\u6807\\u7b7e"},{sort:null,label:"\\u7b80\\u4ecb"},{sort:null,label:"\\u64cd\\u4f5c"}];for(var ci=0;ci<cols.length;ci++){var col=cols[ci];if(col.sort){var cls="sortable";if(currentSort.field===col.sort)cls+=currentSort.dir==="asc"?" sort-asc":" sort-desc";html+='<th class="'+cls+'" data-sort="'+col.sort+'" onclick="toggleSort(\\''+col.sort+'\')">'+col.label+'</th>'}else{html+="<th>"+col.label+"</th>"}}html+="</tr></thead><tbody>";for(var i=0;i<sorted.length;i++){var l=sorted[i];var tagsHtml="";for(var ti=0;ti<(l.tags||[]).length;ti++){var tc=l.role==="partner"?"tag tag-partner":"tag";tagsHtml+='<span class="'+tc+'">'+(l.tags[ti]||"")+"</span>"}var bioHtml=l.bio?'<div class="bio-preview" title="'+l.bio.replace(/"/g,"&quot;")+'">'+l.bio+"</div>":"-";var roleHtml=l.role==="partner"?'<span class="tag tag-partner">\\u5408\\u4f19\\u4eba</span>':'<span class="tag">\\u6267\\u4e1a\\u5f8b\\u5e08</span>';html+='<tr draggable="true" ondragstart="handleDragStart(event,'+i+')" ondragover="handleDragOver(event)" ondrop="handleDrop(event,'+i+')" ondragend="handleDragEnd(event)">'+'<td><span class="drag-handle">\\u2630</span></td>'+'<td><strong>'+(l.name||"")+"</strong></td>"+'<td>'+(l.title||"-")+"</td>"+'<td>'+roleHtml+"</td>"+'<td>'+(tagsHtml||"-")+"</td>"+'<td>'+bioHtml+"</td>"+'<td class="actions-cell"><button onclick="editLawyer('+l.id+')">\\u7f16\\u8f91</button><button class="delete" onclick="deleteLawyer('+l.id+')">\\u5220\\u9664</button></td>'+"</tr>"}html+="</tbody></table>";container.innerHTML=html}
function openModal(id){document.getElementById("lawyerForm").reset();document.getElementById("editId").value="";document.getElementById("modalTitle").textContent="\\u65b0\\u589e\\u5f8b\\u5e08";document.getElementById("photoPreview").innerHTML="";if(id){document.getElementById("modalTitle").textContent="\\u7f16\\u8f91\\u5f8b\\u5e08";var l=lawyers.find(function(x){return x.id===id});if(l){document.getElementById("editId").value=l.id;document.getElementById("fName").value=l.name||"";document.getElementById("fTitle").value=l.title||"";document.getElementById("fRole").value=l.role||"partner";document.getElementById("fBio").value=l.bio||"";document.getElementById("fTags").value=(l.tags||[]).join(", ");document.getElementById("fPhotoUrl").value=l.photo_url||"";updatePhotoPreview(l.photo_url)}}document.getElementById("lawyerModal").classList.add("show")}
function editLawyer(id){openModal(id)}
function closeModal(){document.getElementById("lawyerModal").classList.remove("show")}
async function handleSubmit(e){e.preventDefault();var id=document.getElementById("editId").value;var body={name:document.getElementById("fName").value,title:document.getElementById("fTitle").value,role:document.getElementById("fRole").value,bio:document.getElementById("fBio").value,tags:document.getElementById("fTags").value.split(",").map(function(t){return t.trim()}).filter(function(t){return t}),photo_url:document.getElementById("fPhotoUrl").value};var method=id?"PUT":"POST";var url=API+"/lawyers"+(id?"/"+id:"");try{var res=await fetch(url,{method:method,headers:getHeaders(),body:JSON.stringify(body)});if(!res.ok)throw new Error();showToast(id?"\\u4fee\\u6539\\u5df2\\u4fdd\\u5b58":"\\u65b0\\u589e\\u5df2\\u5b8c\\u6210","success");closeModal();loadLawyers()}catch(err){showToast("\\u4fdd\\u5b58\\u5931\\u8d25","error")}}
async function deleteLawyer(id){if(!confirm("\\u786e\\u5b9a\\u8981\\u5220\\u9664\\u8be5\\u5f8b\\u5e08\\u5417\\uff1f"))return;try{var res=await fetch(API+"/lawyers/"+id,{method:"DELETE",headers:getHeaders()});if(!res.ok)throw new Error();showToast("\\u5df2\\u5220\\u9664","success");loadLawyers()}catch(err){showToast("\\u5220\\u9664\\u5931\\u8d25","error")}}
function handlePhotoUpload(input){var file=input.files[0];if(!file)return;var reader=new FileReader();reader.onload=function(e){var preview=document.getElementById("photoPreview");if(preview)preview.innerHTML='<img src="'+e.target.result+'" style="max-width:120px;max-height:80px;object-fit:cover;border-radius:4px;border:1px solid #ddd;">'};reader.readAsDataURL(file);var progress=document.getElementById("uploadProgress");if(progress){progress.style.display="block";progress.textContent="\\u4e0a\\u4f20\\u4e2d..."}var formData=new FormData();formData.append("image",file);fetch("/api/upload/image",{method:"POST",headers:{"Authorization":"Bearer "+localStorage.getItem("token")},body:formData}).then(function(res){if(!res.ok)throw new Error();return res.json()}).then(function(data){document.getElementById("fPhotoUrl").value=data.url;if(progress)progress.style.display="none";showToast("\\u4e0a\\u4f20\\u6210\\u529f","success")}).catch(function(err){console.error(err);if(progress)progress.textContent="\\u4e0a\\u4f20\\u5931\\u8d25";showToast("\\u4e0a\\u4f20\\u5931\\u8d25\\uff0c\\u8bf7\\u91cd\\u8bd5","error")})}
function updatePhotoPreview(photoUrl){var preview=document.getElementById("photoPreview");if(!preview)return;if(photoUrl){preview.innerHTML='<img src="'+photoUrl+'" style="max-width:120px;max-height:80px;object-fit:cover;border-radius:4px;border:1px solid #ddd;">'}else{preview.innerHTML=""}}
function showToast(msg,type){var toast=document.getElementById("toast");toast.textContent=msg;toast.className="toast"+(type?" "+type:"");setTimeout(function(){toast.classList.add("show")},10);setTimeout(function(){toast.classList.remove("show")},3000)}
window.onclick=function(e){if(e.target&&e.target.className==="modal")closeModal()};loadLawyers();'''

html = '<!DOCTYPE html>\n<html lang="zh-CN">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>律师管理 - 江苏君劭律师事务所</title>\n<link href="https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@300;400;500;700&display=swap" rel="stylesheet">\n<style>\n'+css+'\n</style>\n</head>\n<body>\n'+body+'\n<script>\n'+js+'\n</script>\n</body>\n</html>'

with open(out, 'w', encoding='utf-8') as f:
    f.write(html)

print('Done', len(html), 'chars')
